		loadShader(GL20.GL_FRAGMENT_SHADER, getText("frag.frag"), program);
		validateProgram(program);
		Shader shader = new Shader(program);
		int location = shader.getLoaction("uniformName");
		// use the location variable to set a value for the uniform named "uniformName" in the shader
	}
